784→        buf_C += align_byte - 1;
785→    }
786→    buf_B = out_tensor_ch * in_tensor_ch * sizeof(int8_t); //converted src2
787→    buf_B += align_byte - 1;
788→    buf_size = buf_A + buf_B + buf_C;
