2612→int32_t nn_mat_mult_nt_t_s8_v2(const int8_t *lhs,
2613→            const int8_t *rhs,
2614→            const int32_t *bias,
2615→            int8_t *dst,
2616→            const int32_t *dst_multipliers,
2617→            const int32_t *dst_shifts,
2618→            const int32_t lhs_rows,
2619→            const int32_t rhs_rows,
2620→            const int32_t rhs_cols,
2621→            const int32_t lhs_offset,    //value is in the range of [-127, 128]
2622→            const int32_t dst_offset,    //value is in the range of [-128, 127]
2623→            const int32_t activation_min,
2624→            const int32_t activation_max,
2625→            const int32_t lhs_cols_offset,
2626→            int32_t *contri_buf)
2627→{
2628→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_ELEN64)
2629→    long vl;
2630→    long rhs_rows_idx = 0;
2631→    long max_vl_per_vg_e8m1, max_vl_per_vg_e8m2, max_vl_per_vg_e8m8;
