2686→                rhs_ptr2 += vl;
2687→                rhs_ptr3 += vl;
2688→                rhs_ptr4 += vl;
2689→                lhs_ptr += vl;
2690→                lhs_ptr2 += vl;
2691→                lhs_ptr3 += vl;
2692→                lhs_ptr4 += vl;
2693→
2694→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
