2696→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V1, NDS_VEC_V20, NDS_VEC_V17);
2697→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V2, NDS_VEC_V20, NDS_VEC_V18);
2698→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V3, NDS_VEC_V20, NDS_VEC_V19);
